n, k, m = map(int, input().split())
nums = list(map(int, input().split()))
nums.sort()

def check(nums, m, k):
    for i in range(k):
        if nums[i] % m != nums[k - 1] % m:
            return False
    return True

if check(nums, m, k):
    print("Yes")
    print(*nums[:k])
else:
    print("No")
